import { NextResponse } from 'next/server';

export function middleware(request) {
  const { pathname } = request.nextUrl;

  // Public routes — skip authentication
  if (
    pathname.startsWith('/login') ||
    pathname.startsWith('/api/auth/login') ||
    pathname.startsWith('/_next') ||
    pathname.startsWith('/favicon') ||
    pathname === '/api/auth/me'
  ) {
    return NextResponse.next();
  }

  const token = request.cookies.get('auth_token')?.value;

  // No token → redirect to login (for pages) or 401 (for API)
  if (!token) {
    if (pathname.startsWith('/api/')) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    }
    const loginUrl = new URL('/login', request.url);
    loginUrl.searchParams.set('redirect', pathname);
    return NextResponse.redirect(loginUrl);
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    /*
     * Match all request paths except:
     * - _next/static (static files)
     * - _next/image (image optimization files)
     * - favicon.ico
     */
    '/((?!_next/static|_next/image|favicon.ico).*)',
  ],
};

import './globals.css';
import '../styles/layout.css';
import '../styles/chat.css';

export const metadata = {
  title: 'MYBHEG — WhatsApp Business Panel',
  description: 'Shopify sipariş yönetimi ve WhatsApp müşteri iletişim paneli',
};

export default function RootLayout({ children }) {
  return (
    <html lang="tr">
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="anonymous" />
        <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet" />
      </head>
      <body>
        {children}
      </body>
    </html>
  );
}

/* ====================================================
   MYBHEG v2 — Design System
   Dark-first, premium, WhatsApp-inspired
   ==================================================== */

/* ── CSS Custom Properties ─────────────────────────── */
:root {
  /* Background */
  --bg-primary: #0a0a12;
  --bg-secondary: #12121e;
  --bg-tertiary: #1a1a2e;
  --bg-chat: #0d0d18;
  --bg-hover: rgba(255, 255, 255, 0.04);
  --bg-active: rgba(99, 102, 241, 0.12);
  --bg-glass: rgba(255, 255, 255, 0.03);

  /* Surfaces */
  --surface-card: rgba(26, 26, 46, 0.6);
  --surface-modal: rgba(18, 18, 30, 0.95);
  --surface-tooltip: rgba(30, 30, 50, 0.95);

  /* Accent Colors */
  --accent-primary: #6366f1;
  --accent-primary-hover: #818cf8;
  --accent-green: #10b981;
  --accent-green-light: #34d399;
  --accent-blue: #3b82f6;
  --accent-orange: #f59e0b;
  --accent-red: #ef4444;
  --accent-purple: #8b5cf6;
  --accent-pink: #ec4899;
  --accent-cyan: #06b6d4;

  /* Message Colors */
  --msg-outgoing: #1a3a2a;
  --msg-outgoing-border: rgba(16, 185, 129, 0.2);
  --msg-incoming: #1e1e32;
  --msg-incoming-border: rgba(99, 102, 241, 0.15);
  --msg-system: rgba(139, 92, 246, 0.08);
  --msg-ai: rgba(139, 92, 246, 0.12);

  /* Text */
  --text-primary: #e2e8f0;
  --text-secondary: #94a3b8;
  --text-tertiary: #64748b;
  --text-muted: #475569;
  --text-inverse: #0f172a;
  --text-link: #60a5fa;

  /* Borders */
  --border-primary: rgba(255, 255, 255, 0.06);
  --border-secondary: rgba(255, 255, 255, 0.1);
  --border-focus: rgba(99, 102, 241, 0.5);

  /* Shadows */
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 8px 32px rgba(0, 0, 0, 0.5);
  --shadow-glow: 0 0 20px rgba(99, 102, 241, 0.15);

  /* Radius */
  --radius-xs: 4px;
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;
  --radius-xl: 24px;
  --radius-full: 9999px;

  /* Spacing */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-5: 20px;
  --space-6: 24px;
  --space-8: 32px;
  --space-10: 40px;
  --space-12: 48px;

  /* Typography */
  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;
  --text-xs: 11px;
  --text-sm: 13px;
  --text-base: 14px;
  --text-md: 15px;
  --text-lg: 17px;
  --text-xl: 20px;
  --text-2xl: 24px;
  --text-3xl: 30px;

  /* Layout */
  --sidebar-width: 260px;
  --sidebar-collapsed: 68px;
  --header-height: 56px;
  --chat-list-width: 360px;
  --profile-width: 320px;

  /* Transitions */
  --transition-fast: 150ms ease;
  --transition-base: 200ms ease;
  --transition-slow: 300ms ease;
  --transition-spring: 300ms cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* ── Reset & Base ─────────────────────────────────── */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 14px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-sans);
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.5;
  overflow: hidden;
  height: 100vh;
}

a {
  color: var(--text-link);
  text-decoration: none;
  transition: color var(--transition-fast);
}
a:hover { color: var(--accent-primary-hover); }

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  outline: none;
  background: none;
  color: inherit;
  font-size: inherit;
}

input, textarea, select {
  font-family: inherit;
  font-size: inherit;
  color: var(--text-primary);
  background: var(--bg-secondary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  padding: var(--space-2) var(--space-3);
  outline: none;
  transition: border-color var(--transition-fast), box-shadow var(--transition-fast);
}
input:focus, textarea:focus, select:focus {
  border-color: var(--border-focus);
  box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.1);
}

::placeholder {
  color: var(--text-muted);
}

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.1);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.2);
}

/* ── Utility Classes ──────────────────────────────── */
.truncate {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 8px;
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: 600;
  letter-spacing: 0.02em;
}
.badge-green { background: rgba(16, 185, 129, 0.15); color: var(--accent-green-light); }
.badge-red { background: rgba(239, 68, 68, 0.15); color: #fca5a5; }
.badge-orange { background: rgba(245, 158, 11, 0.15); color: #fcd34d; }
.badge-blue { background: rgba(59, 130, 246, 0.15); color: #93c5fd; }
.badge-purple { background: rgba(139, 92, 246, 0.15); color: #c4b5fd; }
.badge-gray { background: rgba(148, 163, 184, 0.12); color: var(--text-secondary); }

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  font-weight: 500;
  font-size: var(--text-sm);
  transition: all var(--transition-fast);
  white-space: nowrap;
}
.btn:active { transform: scale(0.97); }
.btn-primary {
  background: var(--accent-primary);
  color: white;
}
.btn-primary:hover { background: var(--accent-primary-hover); box-shadow: var(--shadow-glow); }
.btn-secondary {
  background: var(--bg-tertiary);
  color: var(--text-primary);
  border: 1px solid var(--border-secondary);
}
.btn-secondary:hover { background: var(--bg-hover); border-color: var(--border-focus); }
.btn-ghost {
  color: var(--text-secondary);
  padding: 6px 10px;
}
.btn-ghost:hover { background: var(--bg-hover); color: var(--text-primary); }
.btn-danger { background: rgba(239, 68, 68, 0.15); color: #fca5a5; }
.btn-danger:hover { background: rgba(239, 68, 68, 0.25); }
.btn-sm { padding: 4px 10px; font-size: var(--text-xs); }
.btn-icon {
  width: 36px;
  height: 36px;
  padding: 0;
  border-radius: var(--radius-sm);
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.avatar {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
  font-size: var(--text-sm);
  flex-shrink: 0;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-purple));
  color: white;
}
.avatar-sm { width: 32px; height: 32px; font-size: var(--text-xs); }
.avatar-lg { width: 56px; height: 56px; font-size: var(--text-lg); }

/* ── Animations ───────────────────────────────────── */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes slideInLeft {
  from { opacity: 0; transform: translateX(-12px); }
  to { opacity: 1; transform: translateX(0); }
}
@keyframes slideInRight {
  from { opacity: 0; transform: translateX(12px); }
  to { opacity: 1; transform: translateX(0); }
}
@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}
@keyframes messagePop {
  0% { opacity: 0; transform: scale(0.8) translateY(10px); }
  100% { opacity: 1; transform: scale(1) translateY(0); }
}

.animate-fade { animation: fadeIn 0.3s ease forwards; }
.animate-slide-left { animation: slideInLeft 0.3s ease forwards; }
.animate-slide-right { animation: slideInRight 0.3s ease forwards; }
.animate-pulse { animation: pulse 2s ease-in-out infinite; }
.animate-message { animation: messagePop 0.25s cubic-bezier(0.34, 1.56, 0.64, 1) forwards; }

import { NextResponse } from 'next/server';
import { getMany, getOne } from '@/lib/db';

export async function GET(request) {
  try {
    const { searchParams } = new URL(request.url);
    const search = searchParams.get('search') || '';
    const segment = searchParams.get('segment') || 'all';
    const page = parseInt(searchParams.get('page') || '1');
    const limit = 30;
    const offset = (page - 1) * limit;

    const params = [limit, offset];
    let whereClause = 'WHERE 1=1';

    if (search) {
      whereClause += ` AND (c.name ILIKE $${params.length + 1} OR c.phone ILIKE $${params.length + 1} OR sc.email ILIKE $${params.length + 1})`;
      params.push(`%${search}%`);
    }

    if (segment === 'vip') {
      whereClause += ` AND sc.total_spent > 5000`;
    } else if (segment === 'returning') {
      whereClause += ` AND sc.orders_count > 1`;
    } else if (segment === 'new') {
      whereClause += ` AND (sc.orders_count IS NULL OR sc.orders_count <= 1)`;
    }

    const customers = await getMany(`
      SELECT 
        c.id, c.name, c.phone, c.tags, c.metadata, c.created_at, c.updated_at,
        sc.email, sc.first_name, sc.last_name, sc.total_spent, sc.orders_count,
        sc.accepts_marketing, sc.verified_email,
        (SELECT COUNT(*)::int FROM messages m WHERE m.contact_id = c.id) AS message_count,
        (SELECT MAX(m.timestamp) FROM messages m WHERE m.contact_id = c.id) AS last_message_at,
        CASE 
          WHEN sc.total_spent > 5000 THEN 'vip'
          WHEN sc.orders_count > 3 THEN 'loyal'
          WHEN sc.orders_count > 1 THEN 'returning'
          ELSE 'new'
        END AS segment
      FROM contacts c
      LEFT JOIN shopify_customers sc ON sc.phone = c.phone
      ${whereClause}
      ORDER BY c.updated_at DESC
      LIMIT $1 OFFSET $2
    `, params);

    const total = await getOne(`SELECT COUNT(*)::int as count FROM contacts c LEFT JOIN shopify_customers sc ON sc.phone = c.phone ${whereClause.replace(/\$\d+/g, (m) => { const idx = parseInt(m.slice(1)) - 1; return params[idx] ? `'${params[idx]}'` : m; })}`);

    return NextResponse.json({
      success: true,
      data: customers,
      pagination: { page, limit, total: parseInt(total?.count || 0) },
    });
  } catch (error) {
    console.error('Customers API error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { query, getOne } from '@/lib/db';

export async function POST(request) {
  try {
    const body = await request.json();
    const { contact_id, message, type = 'text' } = body;

    if (!contact_id || !message) {
      return NextResponse.json({ success: false, error: 'contact_id and message are required' }, { status: 400 });
    }

    // Get contact phone
    const contact = await getOne('SELECT phone, name FROM contacts WHERE id = $1', [contact_id]);
    if (!contact) {
      return NextResponse.json({ success: false, error: 'Contact not found' }, { status: 404 });
    }

    // Send via WhatsApp Cloud API (through n8n webhook or directly)
    const waPhoneNumberId = process.env.WA_PHONE_NUMBER_ID;
    const waToken = process.env.WA_ACCESS_TOKEN;

    let waResponse = null;
    let phone = contact.phone.replace(/[^0-9]/g, '');

    if (waPhoneNumberId && waToken) {
      try {
        const res = await fetch(`https://graph.facebook.com/v21.0/${waPhoneNumberId}/messages`, {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${waToken}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            messaging_product: 'whatsapp',
            to: phone,
            type: 'text',
            text: { body: message },
          }),
        });
        waResponse = await res.json();
      } catch (waErr) {
        console.error('WhatsApp API error:', waErr);
      }
    }

    // Save message to DB
    const waMessageId = waResponse?.messages?.[0]?.id || null;
    const status = waResponse?.messages ? 'sent' : 'failed';
    const errorMsg = waResponse?.error?.message || null;

    const result = await query(`
      INSERT INTO messages (message_id, user_id, contact_id, direction, type, content, status, source, timestamp, error_message)
      VALUES ($1, 1, $2, 'outgoing', $3, $4, $5, 'operator', NOW(), $6)
      RETURNING id, message_id, direction, type, content, status, source, timestamp
    `, [waMessageId, contact_id, type, message, status, errorMsg]);

    const savedMessage = result.rows[0];

    return NextResponse.json({
      success: true,
      data: savedMessage,
      wa_response: waResponse,
    });
  } catch (error) {
    console.error('Send message error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getMany, getOne } from '@/lib/db';

export async function GET(request) {
  try {
    const { searchParams } = new URL(request.url);
    const search = searchParams.get('search') || '';
    const status = searchParams.get('status') || 'all';
    const page = parseInt(searchParams.get('page') || '1');
    const limit = 30;
    const offset = (page - 1) * limit;

    const params = [limit, offset];
    let whereClause = 'WHERE 1=1';

    if (status !== 'all') {
      whereClause += ` AND p.status = $${params.length + 1}`;
      params.push(status);
    }

    if (search) {
      whereClause += ` AND (p.title ILIKE $${params.length + 1} OR p.vendor ILIKE $${params.length + 1} OR p.product_type ILIKE $${params.length + 1})`;
      params.push(`%${search}%`);
    }

    const products = await getMany(`
      SELECT p.id, p.shopify_id, p.title, p.vendor, p.product_type, p.status,
        p.tags, p.published_at, p.updated_at,
        (SELECT COUNT(*)::int FROM shopify_variants v WHERE v.product_id = p.id) AS variant_count,
        (SELECT MIN(price)::numeric FROM shopify_variants v WHERE v.product_id = p.id) AS min_price,
        (SELECT MAX(price)::numeric FROM shopify_variants v WHERE v.product_id = p.id) AS max_price,
        (SELECT SUM(inventory_quantity)::int FROM shopify_variants v WHERE v.product_id = p.id) AS total_stock,
        (SELECT url FROM shopify_images si WHERE si.product_id = p.id AND si.position = 1 LIMIT 1) AS image_url
      FROM shopify_products p
      ${whereClause}
      ORDER BY p.updated_at DESC NULLS LAST
      LIMIT $1 OFFSET $2
    `, params);

    const total = await getOne(`SELECT COUNT(*)::int as count FROM shopify_products p ${whereClause.replace(/\$\d+/g, (m) => params[parseInt(m.slice(1)) - 1] ? `'${params[parseInt(m.slice(1)) - 1]}'` : m)}`);

    return NextResponse.json({
      success: true,
      data: products,
      pagination: { page, limit, total: parseInt(total?.count || 0) },
    });
  } catch (error) {
    console.error('Products API error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';

export async function POST() {
  const response = NextResponse.json({ success: true });
  response.cookies.set('auth_token', '', {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 0,
    path: '/',
  });
  return response;
}

import { NextResponse } from 'next/server';
import { getSession } from '@/lib/auth';

export async function GET() {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ success: false, error: 'Not authenticated' }, { status: 401 });
    }
    return NextResponse.json({ success: true, user: session });
  } catch {
    return NextResponse.json({ success: false, error: 'Auth check failed' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { authenticateUser, generateToken } from '@/lib/auth';

export async function POST(request) {
  try {
    const { username, password } = await request.json();

    if (!username || !password) {
      return NextResponse.json({ success: false, error: 'Kullanıcı adı ve şifre gerekli' }, { status: 400 });
    }

    const user = await authenticateUser(username, password);
    if (!user) {
      return NextResponse.json({ success: false, error: 'Geçersiz kullanıcı adı veya şifre' }, { status: 401 });
    }

    const token = generateToken(user);

    const response = NextResponse.json({
      success: true,
      user: { id: user.id, username: user.username, role: user.role, display_name: user.display_name },
    });

    response.cookies.set('auth_token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 60 * 60 * 24, // 24 hours
      path: '/',
    });

    return response;
  } catch (error) {
    console.error('Login error:', error);
    return NextResponse.json({ success: false, error: 'Giriş başarısız' }, { status: 500 });
  }
}

