// Update contact tags
export async function PUT(request, { params }) {
  try {
    const { id } = await params;
    const { tags } = await request.json();

    await query(`UPDATE contacts SET tags = $1, updated_at = NOW() WHERE id = $2`, [tags, id]);

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Tags error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { query, getOne } from '@/lib/db';

// Toggle manual mode (add/remove from manual_response_list)
export async function PUT(request, { params }) {
  try {
    const { id } = await params;
    const { manual } = await request.json();

    const contact = await getOne(`SELECT phone FROM contacts WHERE id = $1`, [id]);
    if (!contact) {
      return NextResponse.json({ success: false, error: 'Contact not found' }, { status: 404 });
    }

    if (manual) {
      // Add to manual response list
      await query(`
        INSERT INTO manual_response_list (phone_number, added_by, reason)
        VALUES ($1, 'web_panel', 'Operatör tarafından manuel moda alındı')
        ON CONFLICT (phone_number) DO NOTHING
      `, [contact.phone]);
    } else {
      // Remove from manual response list
      await query(`
        DELETE FROM manual_response_list WHERE phone_number = $1
      `, [contact.phone]);
    }

    return NextResponse.json({ success: true, manual });
  } catch (error) {
    console.error('Manual mode error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { query, getOne } from '@/lib/db';

// Add note
export async function POST(request, { params }) {
  try {
    const { id } = await params;
    const { note, operator_name } = await request.json();

    if (!note) {
      return NextResponse.json({ success: false, error: 'Not içeriği gerekli' }, { status: 400 });
    }

    await query(`
      INSERT INTO conversation_notes (contact_id, operator_name, note)
      VALUES ($1, $2, $3)
    `, [id, operator_name || 'Operator', note]);

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Note error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getMany } from '@/lib/db';

export async function GET(request) {
  try {
    const { searchParams } = new URL(request.url);
    const search = searchParams.get('search') || '';
    const filter = searchParams.get('filter') || 'all';
    const page = parseInt(searchParams.get('page') || '1');
    const limit = 50;
    const offset = (page - 1) * limit;

    let filterClause = '';
    if (filter === 'unread') {
      filterClause = `AND EXISTS (
        SELECT 1 FROM messages m2 
        WHERE m2.contact_id = c.id AND m2.direction = 'incoming' AND m2.status = 'sent'
      )`;
    } else if (filter === 'ai') {
      filterClause = `AND EXISTS (
        SELECT 1 FROM messages m2 
        WHERE m2.contact_id = c.id AND m2.source = 'ai'
      )`;
    } else if (filter === 'pending') {
      filterClause = `AND EXISTS (
        SELECT 1 FROM orders o 
        WHERE o.phone_number = c.phone AND o.status = 'PENDING'
      )`;
    } else if (filter === 'manual') {
      filterClause = `AND EXISTS (
        SELECT 1 FROM manual_response_list mrl 
        WHERE mrl.phone_number = c.phone AND mrl.is_active = TRUE
      )`;
    }

    let searchClause = '';
    const params = [limit, offset];
    if (search) {
      searchClause = `AND (c.name ILIKE $3 OR c.phone ILIKE $3)`;
      params.push(`%${search}%`);
    }

    const conversations = await getMany(`
      SELECT 
        c.id, c.name, c.phone, c.tags, c.metadata, c.updated_at,
        last_msg.content AS last_message,
        last_msg.direction AS last_direction,
        last_msg.timestamp AS last_message_at,
        last_msg.type AS last_msg_type,
        last_msg.source AS last_msg_source,
        last_msg.template_name AS last_template,
        last_msg.button_text AS last_button_text,
        COALESCE(unread.count, 0)::int AS unread_count,
        CASE WHEN mrl.id IS NOT NULL THEN true ELSE false END AS is_manual_mode
      FROM contacts c
      LEFT JOIN LATERAL (
        SELECT content, direction, timestamp, type, source, template_name, button_text
        FROM messages 
        WHERE contact_id = c.id 
        ORDER BY timestamp DESC LIMIT 1
      ) last_msg ON TRUE
      LEFT JOIN LATERAL (
        SELECT COUNT(*)::int AS count 
        FROM messages 
        WHERE contact_id = c.id AND direction = 'incoming' AND status = 'sent'
      ) unread ON TRUE
      LEFT JOIN manual_response_list mrl ON mrl.phone_number = c.phone AND mrl.is_active = TRUE
      WHERE c.user_id = 1 ${filterClause} ${searchClause}
      ORDER BY last_msg.timestamp DESC NULLS LAST
      LIMIT $1 OFFSET $2
    `, params);

    return NextResponse.json({ success: true, data: conversations });
  } catch (error) {
    console.error('Conversations API error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getMany, getOne, query } from '@/lib/db';

export async function GET(request, { params }) {
  try {
    const { id } = await params;
    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get('page') || '1');
    const limit = 100;
    const offset = (page - 1) * limit;

    // Get contact info with Shopify customer data
    const contact = await getOne(`
      SELECT c.*, 
        sc.total_spent, sc.orders_count, sc.email, sc.first_name, sc.last_name,
        sc.verified_email, sc.accepts_marketing,
        CASE WHEN mrl.id IS NOT NULL THEN true ELSE false END AS is_manual_mode
      FROM contacts c
      LEFT JOIN shopify_customers sc ON sc.phone = c.phone
      LEFT JOIN manual_response_list mrl ON mrl.phone_number = c.phone AND mrl.is_active = TRUE
      WHERE c.id = $1
    `, [id]);

    if (!contact) {
      return NextResponse.json({ success: false, error: 'Contact not found' }, { status: 404 });
    }

    // Get messages with attachments
    const messages = await getMany(`
      SELECT m.id, m.message_id, m.direction, m.type, m.content, m.status, m.source,
        m.template_name, m.button_text, m.button_payload, m.reaction,
        m.reply_to_message_id, m.timestamp, m.error_code, m.error_message,
        m.interactive_type, m.interactive_data,
        ma.id AS attachment_id, ma.type AS attachment_type, ma.url AS attachment_url,
        ma.filename AS attachment_filename, ma.caption AS attachment_caption,
        ma.mime_type AS attachment_mime, ma.thumbnail_url AS attachment_thumbnail
      FROM messages m
      LEFT JOIN message_attachments ma ON ma.message_id = m.id
      WHERE m.contact_id = $1
      ORDER BY m.timestamp ASC
      LIMIT $2 OFFSET $3
    `, [id, limit, offset]);

    // Get recent orders for this contact
    const orders = await getMany(`
      SELECT id, order_name, status, total_price, currency, financial_status,
        fulfillment_status, created_at_shopify
      FROM orders 
      WHERE phone_number = $1
      ORDER BY created_at_shopify DESC
      LIMIT 5
    `, [contact.phone]);

    // Get conversation notes
    const notes = await getMany(`
      SELECT cn.*, u.display_name AS author
      FROM conversation_notes cn
      LEFT JOIN users u ON u.id = cn.user_id
      WHERE cn.contact_id = $1
      ORDER BY cn.created_at DESC
      LIMIT 10
    `, [id]);

    // Mark incoming messages as read
    await query(`
      UPDATE messages SET status = 'read' 
      WHERE contact_id = $1 AND direction = 'incoming' AND status = 'sent'
    `, [id]);

    return NextResponse.json({
      success: true,
      data: { contact, messages, orders, notes }
    });
  } catch (error) {
    console.error('Conversation detail error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

