import { NextResponse } from 'next/server';
import { getMany, getOne } from '@/lib/db';

export async function GET(request) {
  try {
    const { searchParams } = new URL(request.url);
    const status = searchParams.get('status') || 'ALL';
    const search = searchParams.get('search') || '';
    const page = parseInt(searchParams.get('page') || '1');
    const limit = 30;
    const offset = (page - 1) * limit;

    let statusClause = '';
    const params = [limit, offset];

    if (status !== 'ALL') {
      statusClause = `AND o.status = $3`;
      params.push(status);
    }

    let searchClause = '';
    if (search) {
      searchClause = `AND (o.order_name ILIKE $${params.length + 1} OR o.customer_name ILIKE $${params.length + 1} OR o.phone_number ILIKE $${params.length + 1})`;
      params.push(`%${search}%`);
    }

    const orders = await getMany(`
      SELECT o.id, o.order_name, o.customer_name, o.phone_number, o.email,
        o.total_price, o.currency, o.status, o.financial_status, o.fulfillment_status,
        o.first_message_sent, o.reminder_sent, o.shopify_tags, o.created_at_shopify,
        (SELECT COUNT(*)::int FROM order_line_items li WHERE li.order_id = o.id) AS item_count
      FROM orders o
      WHERE 1=1 ${statusClause} ${searchClause}
      ORDER BY o.created_at_shopify DESC NULLS LAST
      LIMIT $1 OFFSET $2
    `, params);

    const total = await getOne(`SELECT COUNT(*)::int as count FROM orders WHERE 1=1 ${status !== 'ALL' ? `AND status = '${status}'` : ''}`);

    return NextResponse.json({
      success: true,
      data: orders,
      pagination: { page, limit, total: total?.count || 0 },
    });
  } catch (error) {
    console.error('Orders API error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getOne, getMany, query } from '@/lib/db';

export async function GET(request, { params }) {
  try {
    const { id } = await params;

    const order = await getOne(`
      SELECT o.*, 
        c.name as contact_name
      FROM orders o
      LEFT JOIN contacts c ON c.phone = o.phone_number
      WHERE o.id = $1
    `, [id]);

    if (!order) {
      return NextResponse.json({ success: false, error: 'Sipariş bulunamadı' }, { status: 404 });
    }

    const [lineItems, fulfillments, statusLogs] = await Promise.all([
      getMany(`
        SELECT * FROM order_line_items WHERE order_id = $1 ORDER BY id
      `, [id]),
      getMany(`
        SELECT * FROM order_fulfillments WHERE order_id = $1 ORDER BY created_at DESC
      `, [id]),
      getMany(`
        SELECT * FROM order_status_logs WHERE order_id = $1 ORDER BY created_at DESC LIMIT 20
      `, [id]),
    ]);

    return NextResponse.json({
      success: true,
      data: { ...order, line_items: lineItems, fulfillments, status_logs: statusLogs },
    });
  } catch (error) {
    console.error('Order detail error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

// Update order status
export async function PUT(request, { params }) {
  try {
    const { id } = await params;
    const { status } = await request.json();

    await query(`
      UPDATE orders SET status = $1, updated_at = NOW() WHERE id = $2
    `, [status, id]);

    await query(`
      INSERT INTO order_status_logs (order_id, old_status, new_status, changed_by, source)
      VALUES ($1, (SELECT status FROM orders WHERE id = $1), $2, 'operator', 'web_panel')
    `, [id, status]);

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Order status update error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

