                transition: 'border-color var(--transition-fast)',
              }}
              onFocus={e => e.target.style.borderColor = 'var(--accent-primary)'}
              onBlur={e => e.target.style.borderColor = 'var(--border-primary)'}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%', padding: '14px',
              background: loading ? 'var(--bg-tertiary)' : 'linear-gradient(135deg, var(--accent-primary), var(--accent-purple))',
              border: 'none', borderRadius: 'var(--radius-md)',
              color: '#fff', fontSize: 'var(--text-sm)', fontWeight: 700,
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'all var(--transition-fast)',
              marginTop: '8px',
              boxShadow: loading ? 'none' : '0 4px 16px rgba(99,102,241,0.4)',
            }}
          >
            {loading ? 'Giriş yapılıyor...' : 'Giriş Yap'}
          </button>
        </form>

        <div style={{
          textAlign: 'center', marginTop: '24px',
          fontSize: 'var(--text-xs)', color: 'var(--text-muted)',
        }}>
          Powered by MYBHEG v2
        </div>
      </div>
    </div>
  );
}

/* ── Chat Layout ──────────────────────────────────── */
.chat-layout {
  display: flex;
  height: 100vh;
  overflow: hidden;
}

/* ── Conversation List (Left Panel) ───────────────── */
.conversation-list-panel {
  width: var(--chat-list-width);
  height: 100%;
  border-right: 1px solid var(--border-primary);
  display: flex;
  flex-direction: column;
  background: var(--bg-secondary);
  flex-shrink: 0;
}

.conversation-list-header {
  padding: var(--space-4) var(--space-4) var(--space-3);
  border-bottom: 1px solid var(--border-primary);
}

.conversation-list-title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--space-3);
}

.conversation-list-title h2 {
  font-size: var(--text-lg);
  font-weight: 700;
}

.search-box {
  position: relative;
}

.search-box input {
  width: 100%;
  padding: var(--space-2) var(--space-3) var(--space-2) 34px;
  background: var(--bg-tertiary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-md);
  font-size: var(--text-sm);
  color: var(--text-primary);
}

.search-box-icon {
  position: absolute;
  left: 10px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-muted);
  font-size: 14px;
}

.conversation-filters {
  display: flex;
  gap: var(--space-1);
  padding: var(--space-2) var(--space-4);
  border-bottom: 1px solid var(--border-primary);
  overflow-x: auto;
}

.filter-btn {
  padding: 4px 12px;
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: 500;
  color: var(--text-secondary);
  background: transparent;
  border: 1px solid var(--border-primary);
  white-space: nowrap;
  transition: all var(--transition-fast);
}

.filter-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.filter-btn.active {
  background: var(--accent-primary);
  color: white;
  border-color: var(--accent-primary);
}

/* ── Conversation Items ───────────────────────────── */
.conversation-list {
  flex: 1;
  overflow-y: auto;
}

.conversation-item {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: var(--space-3) var(--space-4);
  cursor: pointer;
  transition: background var(--transition-fast);
  border-bottom: 1px solid var(--border-primary);
  position: relative;
}

.conversation-item:hover {
  background: var(--bg-hover);
}

.conversation-item.active {
  background: var(--bg-active);
  border-left: 3px solid var(--accent-primary);
}

.conversation-item.unread {
  background: rgba(99, 102, 241, 0.05);
}

.conversation-avatar {
  position: relative;
  flex-shrink: 0;
}

.conversation-avatar .online-dot {
  position: absolute;
  bottom: 0;
  right: 0;
  width: 10px;
  height: 10px;
  background: var(--accent-green);
  border: 2px solid var(--bg-secondary);
  border-radius: var(--radius-full);
}

.conversation-info {
  flex: 1;
  min-width: 0;
}

.conversation-info-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-2);
  margin-bottom: 2px;
}

.conversation-name {
  font-size: var(--text-sm);
  font-weight: 600;
  color: var(--text-primary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.conversation-time {
  font-size: var(--text-xs);
  color: var(--text-tertiary);
  flex-shrink: 0;
}

.conversation-preview {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-2);
}

.conversation-last-msg {
  font-size: var(--text-xs);
  color: var(--text-secondary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  flex: 1;
}

.conversation-last-msg .direction-icon {
  color: var(--accent-green);
  margin-right: 2px;
}

.unread-count {
  background: var(--accent-primary);
  color: white;
  font-size: 10px;
  font-weight: 700;
  min-width: 18px;
  height: 18px;
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 5px;
  flex-shrink: 0;
}

.conversation-tags {
  display: flex;
  gap: 3px;
  margin-top: 3px;
}

.conversation-tag {
  font-size: 9px;
  padding: 1px 5px;
  border-radius: var(--radius-full);
  background: rgba(99, 102, 241, 0.1);
  color: var(--accent-primary-hover);
}

/* ── Chat Window (Center Panel) ───────────────────── */
.chat-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  background: var(--bg-chat);
}

.chat-empty {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
  gap: var(--space-4);
}

.chat-empty-icon {
  font-size: 64px;
  opacity: 0.3;
}

.chat-empty-text {
  font-size: var(--text-lg);
  font-weight: 500;
}

.chat-empty-hint {
  font-size: var(--text-sm);
  color: var(--text-tertiary);
}

.chat-header {
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 var(--space-5);
  gap: var(--space-3);
  border-bottom: 1px solid var(--border-primary);
  background: var(--bg-secondary);
  flex-shrink: 0;
}

.chat-header-info {
  flex: 1;
  min-width: 0;
}

.chat-header-name {
  font-size: var(--text-md);
  font-weight: 600;
}

.chat-header-status {
  font-size: var(--text-xs);
  color: var(--text-tertiary);
}

.chat-header-actions {
  display: flex;
  gap: var(--space-2);
}

/* ── Messages Area ────────────────────────────────── */
.messages-container {
  flex: 1;
  overflow-y: auto;
  padding: var(--space-4) var(--space-6);
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.message-date-divider {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-4) 0 var(--space-2);
}

.message-date-divider span {
  background: var(--bg-tertiary);
  color: var(--text-tertiary);
  font-size: var(--text-xs);
  font-weight: 500;
  padding: 3px 12px;
  border-radius: var(--radius-full);
}

.message-row {
  display: flex;
  animation: messagePop 0.25s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.message-row.incoming {
  justify-content: flex-start;
}

.message-row.outgoing {
  justify-content: flex-end;
}

.message-bubble {
  max-width: 65%;
  padding: var(--space-2) var(--space-3);
  border-radius: var(--radius-lg);
  position: relative;
  word-wrap: break-word;
  line-height: 1.45;
  font-size: var(--text-sm);
}

.message-row.incoming .message-bubble {
  background: var(--msg-incoming);
  border: 1px solid var(--msg-incoming-border);
  border-bottom-left-radius: var(--radius-xs);
}

.message-row.outgoing .message-bubble {
  background: var(--msg-outgoing);
  border: 1px solid var(--msg-outgoing-border);
  border-bottom-right-radius: var(--radius-xs);
}

.message-source {
  display: inline-flex;
  align-items: center;
  gap: 3px;
  font-size: 10px;
  font-weight: 600;
  margin-bottom: 2px;
}

.message-source.ai { color: var(--accent-purple); }
.message-source.system { color: var(--accent-orange); }
.message-source.operator { color: var(--accent-cyan); }

.message-content {
  color: var(--text-primary);
  white-space: pre-wrap;
}

.message-content a {
  color: var(--text-link);
  text-decoration: underline;
}

.message-meta {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--space-1);
  margin-top: 2px;
}

.message-time {
  font-size: 10px;
  color: var(--text-muted);
}

.message-status {
  font-size: 11px;
}
.message-status.sent { color: var(--text-muted); }
.message-status.delivered { color: var(--text-secondary); }
.message-status.read { color: var(--accent-blue); }
.message-status.failed { color: var(--accent-red); }

.message-reaction {
  position: absolute;
  bottom: -8px;
  right: 8px;
  background: var(--bg-tertiary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-full);
  padding: 1px 4px;
  font-size: 12px;
}

/* Button messages */
.message-buttons {
  display: flex;
  flex-direction: column;
  gap: var(--space-1);
  margin-top: var(--space-2);
  padding-top: var(--space-2);
  border-top: 1px solid rgba(255,255,255,0.06);
}

.message-btn {
  padding: var(--space-2);
  border-radius: var(--radius-sm);
  font-size: var(--text-xs);
  font-weight: 500;
  text-align: center;
  background: rgba(99, 102, 241, 0.1);
  color: var(--accent-primary-hover);
  transition: background var(--transition-fast);
  cursor: default;
}

/* Attachment previews */
.message-attachment {
  margin-bottom: var(--space-2);
  border-radius: var(--radius-md);
  overflow: hidden;
  max-width: 280px;
}

.message-attachment img {
  width: 100%;
  display: block;
  border-radius: var(--radius-md);
}

.message-attachment-file {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-3);
  background: rgba(255,255,255,0.04);
  border-radius: var(--radius-sm);
  font-size: var(--text-xs);
}

.message-attachment-file-icon {
  font-size: 20px;
}

/* ── Message Input ────────────────────────────────── */
.message-input-area {
  padding: var(--space-3) var(--space-5);
  border-top: 1px solid var(--border-primary);
  background: var(--bg-secondary);
}

.message-input-row {
  display: flex;
  align-items: flex-end;
  gap: var(--space-3);
}

.message-input-wrapper {
  flex: 1;
  position: relative;
}

.message-input-wrapper textarea {
  width: 100%;
  min-height: 42px;
  max-height: 120px;
  padding: 10px var(--space-4);
  background: var(--bg-tertiary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-xl);
  resize: none;
  font-size: var(--text-sm);
  line-height: 1.4;
  color: var(--text-primary);
}

.message-input-wrapper textarea:focus {
  border-color: var(--border-focus);
  box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.08);
}

.send-btn {
  width: 42px;
  height: 42px;
  border-radius: var(--radius-full);
  background: var(--accent-primary);
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
  transition: all var(--transition-fast);
}

.send-btn:hover {
  background: var(--accent-primary-hover);
  box-shadow: var(--shadow-glow);
  transform: scale(1.05);
}

.send-btn:active {
  transform: scale(0.95);
}

.send-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
  transform: none;
}

.message-input-tools {
  display: flex;
  gap: var(--space-1);
  padding-top: var(--space-2);
}

.tool-btn {
  padding: 3px 10px;
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  color: var(--text-tertiary);
  background: transparent;
  border: 1px solid var(--border-primary);
  transition: all var(--transition-fast);
}

.tool-btn:hover {
  background: var(--bg-hover);
  color: var(--text-secondary);
  border-color: var(--border-secondary);
}

.tool-btn.active {
  background: rgba(239, 68, 68, 0.1);
  color: #fca5a5;
  border-color: rgba(239, 68, 68, 0.3);
}

/* ── Profile Panel (Right) ────────────────────────── */
.profile-panel {
  width: var(--profile-width);
  height: 100%;
  border-left: 1px solid var(--border-primary);
  background: var(--bg-secondary);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  flex-shrink: 0;
}

.profile-header {
  padding: var(--space-6) var(--space-5);
  text-align: center;
  border-bottom: 1px solid var(--border-primary);
}

.profile-avatar {
  width: 72px;
  height: 72px;
  border-radius: var(--radius-full);
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-purple));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  font-weight: 700;
  color: white;
  margin: 0 auto var(--space-3);
}

.profile-name {
  font-size: var(--text-lg);
  font-weight: 700;
}

.profile-phone {
  font-size: var(--text-sm);
  color: var(--text-secondary);
  margin-top: 2px;
}

.profile-segment {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  margin-top: var(--space-2);
  padding: 3px 12px;
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: 600;
  background: rgba(99, 102, 241, 0.1);
  color: var(--accent-primary-hover);
}

.profile-section {
  padding: var(--space-4) var(--space-5);
  border-bottom: 1px solid var(--border-primary);
}

.profile-section-title {
  font-size: var(--text-xs);
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  margin-bottom: var(--space-3);
}

.profile-stats {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-2);
}

.profile-stat {
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  padding: var(--space-3);
  text-align: center;
}

.profile-stat-value {
  font-size: var(--text-lg);
  font-weight: 700;
  color: var(--text-primary);
}

.profile-stat-label {
  font-size: var(--text-xs);
  color: var(--text-tertiary);
}

.profile-orders {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.profile-order-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-2) var(--space-3);
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  font-size: var(--text-xs);
}

.profile-order-name {
  font-weight: 600;
}

.profile-order-amount {
  color: var(--accent-green-light);
  font-weight: 600;
}

.profile-tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1);
}

.profile-tag {
  padding: 2px 8px;
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  background: rgba(99, 102, 241, 0.1);
  color: var(--accent-primary-hover);
}

.profile-notes {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.profile-note {
  padding: var(--space-2) var(--space-3);
  background: var(--bg-tertiary);
  border-radius: var(--radius-sm);
  font-size: var(--text-xs);
  color: var(--text-secondary);
  border-left: 2px solid var(--accent-purple);
}

.profile-note-author {
  font-size: 10px;
  color: var(--text-muted);
  margin-top: 2px;
}

/* ── App Layout ────────────────────────────────────── */
.app-layout {
  display: flex;
  height: 100vh;
  overflow: hidden;
}

/* ── Sidebar ──────────────────────────────────────── */
.sidebar {
  width: var(--sidebar-width);
  height: 100vh;
  background: var(--bg-secondary);
  border-right: 1px solid var(--border-primary);
  display: flex;
  flex-direction: column;
  flex-shrink: 0;
  transition: width var(--transition-slow);
  z-index: 100;
}

.sidebar-header {
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 var(--space-5);
  border-bottom: 1px solid var(--border-primary);
  gap: var(--space-3);
}

.sidebar-logo {
  display: flex;
  align-items: center;
  gap: var(--space-3);
}

.sidebar-logo-icon {
  width: 34px;
  height: 34px;
  border-radius: var(--radius-md);
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-purple));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  flex-shrink: 0;
}

.sidebar-logo-text {
  font-size: var(--text-lg);
  font-weight: 700;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-purple));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  letter-spacing: -0.02em;
}

.sidebar-nav {
  flex: 1;
  padding: var(--space-3);
  display: flex;
  flex-direction: column;
  gap: var(--space-1);
  overflow-y: auto;
}

.sidebar-section-label {
  font-size: var(--text-xs);
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  padding: var(--space-4) var(--space-3) var(--space-2);
}

.nav-item {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: var(--space-2) var(--space-3);
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  font-size: var(--text-sm);
  font-weight: 500;
  transition: all var(--transition-fast);
  text-decoration: none;
  position: relative;
}

.nav-item:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.nav-item.active {
  background: var(--bg-active);
  color: var(--accent-primary-hover);
}

.nav-item-icon {
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  flex-shrink: 0;
}

.nav-item-badge {
  margin-left: auto;
  background: var(--accent-red);
  color: white;
  font-size: 10px;
  font-weight: 700;
  min-width: 18px;
  height: 18px;
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 5px;
}

.sidebar-footer {
  padding: var(--space-3);
  border-top: 1px solid var(--border-primary);
}

.sidebar-user {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: var(--space-2) var(--space-3);
  border-radius: var(--radius-sm);
  transition: background var(--transition-fast);
  cursor: pointer;
}
.sidebar-user:hover { background: var(--bg-hover); }

.sidebar-user-info {
  flex: 1;
  min-width: 0;
}
.sidebar-user-name {
  font-size: var(--text-sm);
  font-weight: 600;
  color: var(--text-primary);
}
.sidebar-user-role {
  font-size: var(--text-xs);
  color: var(--text-tertiary);
  text-transform: capitalize;
}

/* ── Main Content ─────────────────────────────────── */
.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  height: 100vh;
  overflow: hidden;
}

.page-header {
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 var(--space-6);
  border-bottom: 1px solid var(--border-primary);
  background: var(--bg-secondary);
  gap: var(--space-4);
  flex-shrink: 0;
}

.page-title {
  font-size: var(--text-lg);
  font-weight: 700;
  color: var(--text-primary);
}

.page-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--space-6);
}

'use client';

function formatTime(ts) {
  if (!ts) return '';
  return new Date(ts).toLocaleTimeString('tr-TR', { hour: '2-digit', minute: '2-digit' });
}

function StatusIcon({ status }) {
  switch (status) {
    case 'sent': return <span className="message-status sent">✓</span>;
    case 'delivered': return <span className="message-status delivered">✓✓</span>;
    case 'read': return <span className="message-status read">✓✓</span>;
    case 'failed': return <span className="message-status failed">✗</span>;
    default: return null;
  }
}

function SourceLabel({ source }) {
  switch (source) {
    case 'ai': return <div className="message-source ai">🤖 AI Yanıt</div>;
    case 'system': return <div className="message-source system">⚙️ Sistem</div>;
    case 'broadcast': return <div className="message-source system">📢 Kampanya</div>;
    default: return null;
  }
}

function AttachmentPreview({ message }) {
  const type = message.attachment_type;
  const url = message.attachment_url;
  const filename = message.attachment_filename;
  const caption = message.attachment_caption;

  if (!type) return null;

  if (type === 'image') {
    return (
      <div className="message-attachment">
        <img src={url} alt={caption || 'Resim'} loading="lazy" />
        {caption && <div style={{ padding: '4px 0', fontSize: 'var(--text-xs)', color: 'var(--text-secondary)' }}>{caption}</div>}
      </div>
    );
  }

  if (type === 'video') {
    return (
      <div className="message-attachment">
        <video src={url} controls style={{ width: '100%', borderRadius: 'var(--radius-md)' }} />
        {caption && <div style={{ padding: '4px 0', fontSize: 'var(--text-xs)', color: 'var(--text-secondary)' }}>{caption}</div>}
      </div>
    );
  }

  if (type === 'audio') {
    return (
      <div className="message-attachment" style={{ maxWidth: '240px' }}>
        <audio src={url} controls style={{ width: '100%' }} />
      </div>
    );
  }

  // Document / others
  return (
    <div className="message-attachment-file">
      <span className="message-attachment-file-icon">📄</span>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div className="truncate" style={{ fontWeight: 500 }}>{filename || 'Dosya'}</div>
        <div style={{ color: 'var(--text-muted)', fontSize: '10px' }}>{type}</div>
      </div>
      {url && <a href={url} target="_blank" rel="noopener" style={{ color: 'var(--text-link)', fontSize: 'var(--text-xs)' }}>İndir</a>}
    </div>
  );
}

